mapper.select:
SELECT p.exam_paper_id, p.paper_code, p.paper_name, p.module_name, p.subject_type, p.book_code, p.test_no, p.create_time, b.bank_name, b.exam_type AS exam_category FROM exam_paper p JOIN exam_bank b ON b.exam_bank_id = p.exam_bank_id WHERE p.delete_flag = '1' AND p.status = 1 AND b.delete_flag = '1' AND b.status = 1 AND b.exam_type = 'IELTS'
AND LOWER(p.subject_type) = #{subjectType}
ORDER BY p.subject_type ASC, p.book_code ASC, p.test_no ASC, p.exam_paper_id ASC

SELECT mockexam_paper_set_id, set_name, exam_category, exam_content, paper_count, status, remark, create_time, update_time FROM mockexam_paper_set WHERE delete_flag = '1' AND status = 1
AND exam_category = #{examCategory}
AND exam_content = #{examContent}
ORDER BY create_time DESC, mockexam_paper_set_id DESC

SELECT i.mockexam_paper_set_id, i.exam_paper_id, i.sort_order, p.paper_name, p.paper_code, p.subject_type, p.status AS paper_status, b.status AS bank_status FROM mockexam_paper_set_item i JOIN exam_paper p ON p.exam_paper_id = i.exam_paper_id JOIN exam_bank b ON b.exam_bank_id = p.exam_bank_id WHERE i.delete_flag = '1' AND p.delete_flag = '1' AND b.delete_flag = '1' AND b.exam_type = 'IELTS' AND p.status = 1 AND b.status = 1 AND i.mockexam_paper_set_id IN
#{paperSetId}
ORDER BY i.mockexam_paper_set_id ASC, COALESCE(i.sort_order, 0), i.mockexam_paper_set_item_id ASC

SELECT mockexam_submission_id, exam_paper_id, paper_code, title, exam_category, exam_content,
       score_percent, total_questions, correct_count, wrong_count, gradable_questions,
       elapsed_seconds, payload_json, create_time
FROM mockexam_submission
WHERE user_id = #{userId}
  AND delete_flag = '1'
  AND status = 1

  AND exam_content = #{examContent}

ORDER BY create_time DESC, mockexam_submission_id DESC
LIMIT #{limit}

SELECT f.mockexam_question_favorite_id, f.exam_question_id, f.exam_paper_id, f.paper_code, f.paper_title, f.exam_content, f.exam_section_id, f.exam_group_id, f.question_id, f.question_no, f.question_type, f.stat_type, f.create_time, s.section_title, g.group_title, COALESCE(NULLIF(q.stem_text, ''), NULLIF(q.content_text, ''), q.stem_html, q.content_html, '') AS preview_source FROM mockexam_question_favorite f LEFT JOIN exam_section s ON s.exam_section_id = f.exam_section_id LEFT JOIN exam_group g ON g.exam_group_id = f.exam_group_id LEFT JOIN exam_question q ON q.exam_question_id = f.exam_question_id WHERE f.user_id = #{userId} AND f.delete_flag = '1'
AND f.exam_paper_id = #{examPaperId}
ORDER BY f.create_time DESC, f.mockexam_question_favorite_id DESC LIMIT #{limit}

SELECT mockexam_question_favorite_id
FROM mockexam_question_favorite
WHERE user_id = #{userId}
  AND exam_question_id = #{examQuestionId}
ORDER BY mockexam_question_favorite_id DESC
LIMIT 1

SELECT mockexam_question_favorite_id
FROM mockexam_question_favorite
WHERE user_id = #{userId}
  AND exam_question_id = #{examQuestionId}
  AND delete_flag = '1'
LIMIT 1

SELECT exam_group_id, exam_section_id, group_id, group_title, raw_type, stat_type, instructions_html, instructions_text, content_html, content_text, has_shared_options, has_blanks, primary_image_asset_id, structure_json, sort_order FROM exam_group WHERE delete_flag = '1' AND status = 1 AND exam_section_id IN
#{sectionId}
ORDER BY COALESCE(sort_order, 0), exam_group_id

SELECT exam_question_id, exam_group_id, question_id, question_code, question_no, raw_type, stat_type, stem_html, stem_text, content_html, content_text, source_blank_id, sort_order, score FROM exam_question WHERE delete_flag = '1' AND status = 1 AND exam_group_id IN
#{groupId}
ORDER BY COALESCE(sort_order, 0), COALESCE(question_no, 0), exam_question_id

SELECT exam_group_option_id, exam_group_id, option_key, option_html, option_text, sort_order FROM exam_group_option WHERE delete_flag = '1' AND status = 1 AND exam_group_id IN
#{groupId}
ORDER BY COALESCE(sort_order, 0), exam_group_option_id

SELECT exam_question_answer_id, exam_question_id, answer_raw, answer_json FROM exam_question_answer WHERE delete_flag = '1' AND status = 1 AND exam_question_id IN
#{questionId}
ORDER BY exam_question_answer_id

SELECT exam_question_blank_id, exam_question_id, blank_id, sort_order FROM exam_question_blank WHERE delete_flag = '1' AND status = 1 AND exam_question_id IN
#{questionId}
ORDER BY COALESCE(sort_order, 0), exam_question_blank_id

SELECT exam_asset_id, exam_section_id, exam_group_id, exam_question_id, asset_type, asset_role, asset_name, source_path, storage_path, asset_url, sort_order FROM exam_asset WHERE delete_flag = '1' AND status = 1 AND (
OR exam_section_id IN
#{sectionId}
OR exam_group_id IN
#{groupId}
OR exam_question_id IN
#{questionId}
) ORDER BY COALESCE(sort_order, 0), exam_asset_id

