UPDATE mockexam_progress
SET status = 2,
    mockexam_submission_id = #{submissionId},
    elapsed_seconds = #{elapsedSeconds},
    last_active_time = #{now},
    update_time = #{now}
WHERE mockexam_progress_id = #{progressId}
  AND user_id = #{userId}

UPDATE mockexam_progress
SET status = 0,
    last_active_time = #{now},
    update_time = #{now}
WHERE mockexam_progress_id = #{progressId}
  AND user_id = #{userId}

UPDATE mockexam_question_favorite
SET delete_flag = '0',
    update_time = #{now}
WHERE user_id = #{userId}
  AND exam_question_id = #{examQuestionId}

UPDATE mockexam_wrong_question_stat
SET status = 0,
    delete_flag = '0',
    update_time = #{now}
WHERE user_id = #{userId}
  AND delete_flag = '1'
  AND status = 1
  AND exam_question_id IN

    #{examQuestionId}

UPDATE mockexam_entity_favorite
SET status = 0,
    delete_flag = '0',
    update_time = #{now}
WHERE user_id = #{userId}
  AND target_type = #{targetType}
  AND target_id = #{targetId}
